// Function node (NOT Function Item)
// Input: items[0].json = your event object (normalized or raw)

// --- Helpers ---
function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// Try to build an agenda array from event.agenda or rawDescription/description
function parseAgenda(event) {
  // 1) If agenda is already filled, use it
  if (Array.isArray(event.agenda) && event.agenda.length > 0) {
    return event.agenda;
  }

  const raw = String(event.rawDescription || event.description || '').trim();
  if (!raw) return [];

  const items = [];

  // 2) Parse <li>...</li> from HTML
  const liRegex = /<li[^>]*>(.*?)<\/li>/gis;
  let match;
  while ((match = liRegex.exec(raw)) !== null) {
    let text = match[1]
      .replace(/<br\s*\/?>/gi, ' ')   // <br> -> space
      .replace(/<\/?[^>]+>/g, '')    // strip any nested tags
      .trim();

    if (text) items.push(text);
  }

  if (items.length) return items;

  // 3) Fallback: look for "Agenda:" and split lines/bullets
  const lower = raw.toLowerCase();
  const idx = lower.indexOf('agenda:');
  if (idx !== -1) {
    const after = raw.slice(idx + 'agenda:'.length);
    const normalized = after.replace(/<br\s*\/?>/gi, '\n');

    normalized
      .split('\n')
      .map(line => line.replace(/^[-•]\s*/, '').trim())
      .forEach(line => {
        if (line) items.push(line);
      });
  }

  return items;
}

const event = items[0].json;
const eventId = event.eventId || event.id;            // support both shapes
const eventUpdated = event.updated || event.created;  // best-effort version marker

// --- Resolve start datetime string & timezone ---
const startStr =
  event.start?.dateTime ||    // raw Google Calendar
  event.start ||              // normalized string
  null;

if (!startStr) {
  throw new Error('No start dateTime found on this item.');
}

const tz =
  event.startTimeZone ||
  event.start?.timeZone ||
  'UTC';

const startDate = new Date(startStr);

// --- Build human-friendly schedule line for the email ---
const datePartHuman = new Intl.DateTimeFormat('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  year: 'numeric',
  timeZone: tz,
}).format(startDate);

const timePartHuman = new Intl.DateTimeFormat('en-US', {
  hour: 'numeric',
  minute: '2-digit',
  timeZone: tz,
  timeZoneName: 'short',
}).format(startDate);

const scheduleLine = `${datePartHuman} at ${timePartHuman}`;

// --- Compute reminderAt: same date as start, 08:00:00 with same offset ---
const match = startStr.match(
  /^(\d{4}-\d{2}-\d{2})T.*?(Z|[+-]\d{2}:\d{2})$/
);

if (!match) {
  throw new Error('startStr is not in expected ISO format: ' + startStr);
}

const datePartISO = match[1];   // "2025-11-17"
const offsetISO   = match[2];   // "-06:00" or "Z"

// This is what you'll use in the Wait node:
const reminderAt = `${datePartISO}T08:00:00${offsetISO}`;

// --- Build the email content ---

const title = event.title || event.summary || 'Meeting';
const zoomLink = event.zoomLink || event.location || '#';

// Build agenda list (from agenda[] or rawDescription)
const agendaList = parseAgenda(event);

// Agenda list HTML
const agendaItemsHtml = agendaList
  .map(item => `<li>${escapeHtml(item)}</li>`)
  .join('');

// Email subject
const subject = `Meeting Reminder – ${title}`;

// HTML email body
const html = `
<!DOCTYPE html>
<html lang="en">
  <body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif;color:#111827;">
    <table role="presentation" cellpadding="0" cellspacing="0" width="100%">
      <tr>
        <td align="center" style="padding:24px;">
          <table role="presentation" cellpadding="0" cellspacing="0" width="760" style="max-width:760px;background:#ffffff;border:1px solid #e5e7eb;border-radius:8px;overflow:hidden;">
            <!-- Header -->
            <tr>
              <td bgcolor="#F17D19"
                  style="background:#F17D19;color:#ffffff;padding:16px 28px;border-radius:8px 8px 0 0;text-align:center;">
                <h1 style="margin:0;font-size:20px;font-weight:700;">Meeting Reminder</h1>
                <p style="margin:4px 0 0;font-size:14px;">
                  Scheduled for <strong>${escapeHtml(scheduleLine)}</strong>
                </p>
              </td>
            </tr>

            <!-- Body -->
            <tr>
              <td style="padding:24px 28px;font-size:14px;line-height:1.6;">
                <p style="margin:0 0 16px;">Good day!</p>

                <p style="margin:0 0 16px;">
                  Hope you're doing well! Just a quick reminder about our meeting,
                  <strong>${escapeHtml(scheduleLine)}</strong>.
                  We'll use this time to connect, walk through your questions, and align on next steps.
                  To help things go smoothly, it would be great if:
                </p>

                <ul style="margin:0 0 16px 20px;padding:0;">
                  <li>You can join from a quiet, comfy spot so we can hear each other clearly.</li>
                  <li>In case you’ll be sharing your screen, kindly give it a quick test beforehand.</li>
                </ul>

                <p style="margin:0 0 8px;font-weight:600;">Agenda</p>
                <ul style="margin:0 0 16px 20px;padding:0;">
                  ${agendaItemsHtml}
                </ul>

                <p style="margin:0 0 16px;">
                  Here's the link for your convenience:
                  <a href="${escapeHtml(zoomLink)}" target="_blank" style="color:#2563eb;text-decoration:underline;">
                    ${escapeHtml(zoomLink)}
                  </a>
                </p>

                <table role="presentation" cellpadding="0" cellspacing="0" style="margin:0 0 24px;">
                  <tr>
                    <td align="left">
                      <a href="${escapeHtml(zoomLink)}" target="_blank"
                        style="
                          display:inline-block;
                          padding:10px 18px;
                          border-radius:6px;
                          border:1px solid #2563eb;
                          text-decoration:none;
                          font-size:14px;
                          font-weight:500;
                          color:#2563eb;
                          background:#ffffff;
                        ">
                        Join the Meeting
                      </a>
                    </td>
                  </tr>
                </table>

                <p style="margin:0;">We look forward to speaking with you later!</p>
              </td>
            </tr>

          </table>
        </td>
      </tr>
    </table>
  </body>
</html>
`;

// Optional plain-text version
const text = `
Meeting Reminder

Scheduled for ${scheduleLine}

Good day!

Hope you're doing well! Just a quick reminder about our meeting.
We'll use this time to connect, walk through your questions, and align on next steps.

Agenda:
${agendaList.map(a => `- ${a}`).join('\n')}

Join the meeting: ${zoomLink}

We look forward to speaking with you later!
`.trim();

return [
  {
    json: {
      subject,
      html,
      text,
      reminderAt,
      eventId,       // used after Wait to refetch the event
      eventUpdated,  // used in IF to block stale reminders
    },
  },
];

// n8n Function node
// Normalizes Google Calendar event(s) into a cleaner shape

function parseSummary(summary) {
  // Example: "Initial Process Engineering Call: Kerri Davis [Multiple VAs]"
  const result = {
    title: summary ?? '',
    meetingType: null,
    clientName: null,
    extraLabel: null,
  };

  if (!summary) return result;

  // Split at the first colon
  const m = summary.match(/^([^:]+):\s*(.+)$/);
  if (m) {
    result.meetingType = m[1].trim();  // "Initial Process Engineering Call"
    let rest = m[2].trim();            // "Kerri Davis [Multiple VAs]"

    const bracket = rest.match(/^(.+?)\s*\[(.+?)\]\s*$/);
    if (bracket) {
      result.clientName = bracket[1].trim();  // "Kerri Davis"
      result.extraLabel = bracket[2].trim();  // "Multiple VAs"
    } else {
      result.clientName = rest;
    }
  }

  return result;
}

function extractZoomLink(event) {
  const candidates = [];

  if (event.location && /^https?:\/\//i.test(event.location)) {
    candidates.push(event.location);
  }

  const desc = event.description || '';
  const urlRegex = /(https?:\/\/[^\s"<]+)/ig;

  let match;
  while ((match = urlRegex.exec(desc)) !== null) {
    candidates.push(match[1]);
  }

  // Prefer Zoom, fall back to the first URL if any
  const zoom = candidates.find(u => u.includes('zoom.us')) || candidates[0];
  return zoom || null;
}

function extractAgenda(description) {
  if (!description) return [];

  // Convert <br> to newlines, remove tags
  let text = description
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/\r/g, '');

  const lines = text
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean);

  const bullets = [];
  for (const line of lines) {
    const m = line.match(/^[-•]\s*(.+)$/);
    if (m) {
      bullets.push(m[1].trim());
    }
  }

  return bullets;
}

const newItems = [];

for (const item of items) {
  const ev = item.json;

  const summaryInfo = parseSummary(ev.summary || '');
  const agenda      = extractAgenda(ev.description || '');
  const zoomLink    = extractZoomLink(ev);

  const attendees = (ev.attendees || []).map(a => ({
    email: a.email,
    displayName: a.displayName || null,
    responseStatus: a.responseStatus || null,
    organizer: !!a.organizer,
    optional: !!a.optional,
    self: !!a.self,
  }));

  newItems.push({
    json: {
      // Core IDs / links
      eventId: ev.id,
      iCalUID: ev.iCalUID,
      status: ev.status,
      htmlLink: ev.htmlLink,

      // Parsed summary
      title: ev.summary || null,
      meetingType: summaryInfo.meetingType, // "Initial Process Engineering Call"
      clientName: summaryInfo.clientName,   // "Kerri Davis"
      extraLabel: summaryInfo.extraLabel,   // "Multiple VAs"

      // Schedule
      start: ev.start?.dateTime || ev.start?.date || null,
      end: ev.end?.dateTime || ev.end?.date || null,
      startTimeZone: ev.start?.timeZone || null,
      endTimeZone: ev.end?.timeZone || null,

      // Meeting details
      zoomLink,
      agenda,                          // ["PDEV Methodology Discussion", "Short client interview", ...]
      rawDescription: ev.description || null,
      location: ev.location || null,

      // People
      organizerEmail: ev.organizer?.email || null,
      creatorEmail: ev.creator?.email || null,
      attendees,
    },
  });
}

return newItems;

