  const zoomLink    = extractZoomLink(ev);

  const attendees = (ev.attendees || []).map(a => ({
    email: a.email,
    displayName: a.displayName || null,
    responseStatus: a.responseStatus || null,
    organizer: !!a.organizer,
    optional: !!a.optional,
    self: !!a.self,
  }));

  newItems.push({
    json: {
      // Core IDs / links
      eventId: ev.id,
      iCalUID: ev.iCalUID,
      status: ev.status,
      htmlLink: ev.htmlLink,

      // Extra meta from Calendar
      created: ev.created || null,
      updated: ev.updated || null,
      sequence: ev.sequence ?? null,
      eventType: ev.eventType || null,

      // Parsed summary
      title: ev.summary || null,
      meetingType: summaryInfo.meetingType, // e.g. "Follow-Up PEC"
      clientName: summaryInfo.clientName,   // e.g. "Bill Murray"
      extraLabel: summaryInfo.extraLabel,   // e.g. "PM Handbook Creation"

      // Schedule
      start: ev.start?.dateTime || ev.start?.date || null,
      end: ev.end?.dateTime || ev.end?.date || null,
      startTimeZone: ev.start?.timeZone || null,
      endTimeZone: ev.end?.timeZone || null,

      // Meeting details
      zoomLink,
      agenda,                          // ["Our discussion on the Move-in and Move-out process"]
      rawDescription: ev.description || null,
      location: ev.location || null,

      // People
      organizerEmail: ev.organizer?.email || null,
